// When color picker changes, update hex input
document.querySelectorAll('input[type="color"]').forEach((picker) => {
  picker.addEventListener('input', (event) => {
    let hexInput = document.getElementById(event.target.id + 'Hex');
    hexInput.value = event.target.value;
  });
});

// When hex input changes, update color picker
document.querySelectorAll('input[type="text"]').forEach((hexInput) => {
  hexInput.addEventListener('input', (event) => {
    let colorId = event.target.id.replace('Hex', '');
    let colorPicker = document.getElementById(colorId);
    colorPicker.value = event.target.value;
  });
});
